(223, 75, 1, 'comprehension',
INSERT INTO question_choices (question_id, choice_number, choice_text) VALUES
(223, 1, 'AI detection software has proven highly reliable and is now the primary tool used by universities worldwide to identify and penalize students who submit AI-generated work.'),
(223, 2, 'Detection tools produced numerous false positives, disproportionately flagging the work of non-native English speakers and raising concerns about systematic bias rather than ensuring fairness.'),
(223, 3, 'Universities collaborated with AI companies to develop improved detection algorithms that reduced false positive rates to below five percent within the first year of deployment.'),
(223, 4, 'The accuracy of detection software has improved steadily each year since its introduction, making it an increasingly viable solution to the problem of AI-assisted plagiarism.'),
(224, 1, 'Students who use AI writing tools are more likely to commit outright plagiarism by submitting work that is entirely machine-generated, undermining the value of their degrees.'),
(224, 2, 'Employers have begun to devalue degrees from institutions that permit AI use, making graduates of such programs less competitive in an increasingly demanding job market.'),
(224, 3, 'Reliance on AI eliminates students'' capacity for creative expression, producing a generation of graduates who can analyze but cannot generate original ideas or artistic works.'),
(224, 4, 'Writing serves as a mode of thinking, and if AI handles the demanding work of drafting and revision, students may lose the cognitive struggle that makes writing educationally valuable.'),
(225, 1, 'markedly higher grades and greater confidence in their writing abilities, suggesting that AI tools effectively accelerated their academic development'),
(225, 2, 'comparable performance on most assessments but significantly greater efficiency in completing assignments within shorter timeframes'),
(225, 3, 'measurable declines in analytical reasoning and argumentative coherence, indicating that the cognitive benefits of unaided composition had been forfeited'),
(225, 4, 'improved speed in producing written work but no measurable difference in the depth or originality of their ideas across all subject areas');
